import{_ as t,o,c as a,a3 as r}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"API 测试工具","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/api-tester.md","filePath":"user-guide/tools/api-tester.md","lastUpdated":1779918913000}'),l={name:"user-guide/tools/api-tester.md"};function d(n,e,i,s,c,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<div><h1 id="api-测试工具" tabindex="-1">API 测试工具 <a class="header-anchor" href="#api-测试工具" aria-label="Permalink to &quot;API 测试工具&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>API 测试工具是一个面向开发者的 HTTP 接口调试利器，尤其针对 REST、GraphQL、Webhook 与 LLM API 进行了预设优化。它采用 <strong>预设驱动</strong> 的设计——选择预设即可自动填充 URL、请求头和请求体模板，再通过变量系统微调参数，无需重复手动拼装。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>预设驱动，开箱即用</strong>：内置 REST、GraphQL、Webhook、OpenAI、Gemini、Claude、DeepSeek、DashScope、Moonshot、OpenRouter、本地模型等预设，预设涵盖完整的 URL 模板、变量定义与请求体结构</li><li><strong>智能变量模板系统</strong>：URL、请求头、请求体均支持 <code>{{variable}}</code> 占位符，修改变量值即可一键应用到全请求，告别手工替换</li><li><strong>流式响应原生支持</strong>：自动检测 <code>text/event-stream</code> 内容类型，实时逐块渲染流式输出；支持通过 AbortController 随时中止请求</li><li><strong>请求配置管理</strong>：可将当前请求配置保存为「请求档案」，存入浏览器 <code>localStorage</code>，随时加载复用</li><li><strong>多 API 授权适配</strong>：根据预设类型自动构建或预填鉴权头（如 <code>Authorization: Bearer ...</code>、Anthropic <code>x-api-key</code>），无需手动填写认证格式</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="首次使用-5-步走" tabindex="-1">首次使用 5 步走 <a class="header-anchor" href="#首次使用-5-步走" aria-label="Permalink to &quot;首次使用 5 步走&quot;">​</a></h3><p><strong>第一步：进入工具</strong></p><p>在左侧工具列表中找到 <strong>API 测试工具</strong>，点击进入。你将看到一个左右分栏的界面，顶部是预设选择和 URL 构建区。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注预设选择器、URL 构建器、左侧请求配置区和右侧响应查看区</p></blockquote><p><strong>第二步：选择一个预设</strong></p><p>点击顶部的 <strong>预设选择器</strong> 下拉框，选择一个预设开始：</p><table tabindex="0"><thead><tr><th>预设类别</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>空白 / REST / GraphQL / Webhook</strong></td><td>构建通用 HTTP 请求、JSON 提交、GraphQL 查询和回调测试</td></tr><tr><td><strong>OpenAI / Responses / Embeddings</strong></td><td>测试 OpenAI 聊天、Responses 和向量化接口</td></tr><tr><td><strong>DeepSeek / DashScope / Moonshot / 智谱 / OpenRouter / Groq / xAI</strong></td><td>测试 OpenAI 兼容服务商接口</td></tr><tr><td><strong>Ollama / LM Studio</strong></td><td>测试本地 OpenAI 兼容模型服务</td></tr><tr><td><strong>Google Gemini / Anthropic / Cohere</strong></td><td>测试非 OpenAI 协议或独立服务商 API</td></tr></tbody></table><p>选择后，URL、请求头和请求体会自动填充。</p><blockquote><p>TODO: 截图 - 预设选择器展开状态，显示多类预设选项</p></blockquote><p><strong>第三步：填写关键变量</strong></p><p>左侧的 <strong>URL 变量</strong> 区域列出了该预设所需的所有变量（如 <code>baseUrl</code>、<code>apiKey</code>、<code>model</code> 等）。部分变量带有下拉选项（如 <code>protocol</code> 可选 http/https），部分需要手动输入。</p><p>至少要填写以下内容：</p><ol><li><strong>API Key</strong> —— 你的 API 密钥（部分预设必填；保存档案时会随变量一起存入本地 <code>localStorage</code>）</li><li><strong>Base URL</strong> —— 如果是第三方兼容接口，改为对应的地址（如 <code>api.deepseek.com</code>）</li><li><strong>模型</strong> —— 选择或输入你要测试的模型名称</li><li><strong>用户消息</strong> —— 输入一段测试消息</li></ol><blockquote><p>TODO: 截图 - 变量编辑区域高亮，标注必填变量</p></blockquote><p><strong>第四步：调整请求细节</strong></p><p>在左侧的 <strong>请求配置</strong> 面板中，你可以：</p><ul><li>查看和编辑自动生成的 <strong>请求头</strong>（如 Content-Type）</li><li>在 <strong>请求体</strong> 编辑器中修改 JSON 请求体模板</li></ul><blockquote><p>TODO: 截图 - 请求配置面板，标注请求头表格和请求体编辑器</p></blockquote><p><strong>第五步：发送并查看响应</strong></p><p>点击顶部的 <strong>发送</strong> 按钮，请求发出后右侧的 <strong>响应面板</strong> 会显示：</p><ul><li><strong>状态码</strong> 和 <strong>状态文本</strong>（如 <code>200 OK</code>）</li><li><strong>响应头</strong> 列表</li><li><strong>响应体</strong> 内容（JSON 自动格式化，流式内容实时追加）</li><li><strong>耗时</strong>（从发起到收到完整响应的时间）</li></ul><blockquote><p>TODO: 截图 - 收到正常响应后的界面，标注状态码、响应头和格式化后的响应体</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="url-构建器" tabindex="-1">URL 构建器 <a class="header-anchor" href="#url-构建器" aria-label="Permalink to &quot;URL 构建器&quot;">​</a></h3><p>顶部横跨全宽的 URL 构建器包含三个核心元素：</p><table tabindex="0"><thead><tr><th>元素</th><th>说明</th></tr></thead><tbody><tr><td><strong>方法选择器</strong></td><td>下拉框切换 HTTP 方法（GET / POST / PUT / DELETE / PATCH）</td></tr><tr><td><strong>URL 输入框</strong></td><td>显示完整的请求 URL，变量已被替换为实际值（只读显示）</td></tr><tr><td><strong>发送按钮</strong></td><td>发起请求；请求进行中时变为 <strong>停止</strong> 按钮，点击可中止当前请求</td></tr></tbody></table><p>URL 输入框显示的是变量替换后的最终 URL，让你在发送前确认地址无误。</p><blockquote><p>TODO: 截图 - URL 构建器，标注方法选择器、URL 显示区域和发送/停止按钮</p></blockquote><h3 id="变量系统" tabindex="-1">变量系统 <a class="header-anchor" href="#变量系统" aria-label="Permalink to &quot;变量系统&quot;">​</a></h3><p>变量是 API 测试工具最核心的灵活机制。</p><h4 id="变量编辑器-url-变量区域" tabindex="-1">变量编辑器（URL 变量区域） <a class="header-anchor" href="#变量编辑器-url-变量区域" aria-label="Permalink to &quot;变量编辑器（URL 变量区域）&quot;">​</a></h4><p>左侧的 URL 变量区域列出当前预设定义的所有变量。每个变量包含：</p><ul><li><strong>标签</strong>（如 &quot;Base URL&quot;、&quot;模型&quot;）</li><li><strong>输入控件</strong>（根据 <code>type</code> 自动适配：文本输入框、下拉选择器、切换开关）</li><li><strong>必填标记</strong>（必填变量旁有红色 <code>*</code> 标记）</li><li><strong>说明文字</strong>（鼠标悬停或输入框下方显示提示）</li></ul><blockquote><p>TODO: 截图 - 变量编辑器，标注不同类型的变量控件（文本框、下拉框、开关）</p></blockquote><h4 id="变量类型" tabindex="-1">变量类型 <a class="header-anchor" href="#变量类型" aria-label="Permalink to &quot;变量类型&quot;">​</a></h4><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>交互方式</th></tr></thead><tbody><tr><td><code>string</code></td><td>文本字符串</td><td>文本输入框</td></tr><tr><td><code>enum</code></td><td>枚举选项列表</td><td>下拉选择器</td></tr><tr><td><code>boolean</code></td><td>布尔值</td><td>开关切换器</td></tr></tbody></table><h4 id="变量的作用范围" tabindex="-1">变量的作用范围 <a class="header-anchor" href="#变量的作用范围" aria-label="Permalink to &quot;变量的作用范围&quot;">​</a></h4><p>变量的作用是 <strong>全局模板替换</strong>——URL、请求头、请求体中的所有 <code>{{variableName}}</code> 占位符都会在发送时被替换为当前变量值。例如，修改 <code>model</code> 变量为 <code>deepseek-chat</code>，URL 和请求体中的 <code>{{model}}</code> 会全部自动替换。</p><blockquote><p>💡 <strong>小提示</strong>：你可以通过「配置」按钮打开配置管理对话框，添加自定义变量，扩展预设的能力。</p></blockquote><h3 id="请求配置面板" tabindex="-1">请求配置面板 <a class="header-anchor" href="#请求配置面板" aria-label="Permalink to &quot;请求配置面板&quot;">​</a></h3><p>位于左下方的请求配置面板包含两个选项卡：</p><h4 id="请求头" tabindex="-1">请求头 <a class="header-anchor" href="#请求头" aria-label="Permalink to &quot;请求头&quot;">​</a></h4><p>一个键值对表格，列出当前请求的所有 HTTP 头。预设已经自动填充了必要的头（如 <code>Content-Type: application/json</code>，Anthropic 还会自动添加 <code>anthropic-version</code>）。你可以：</p><ul><li><strong>编辑值</strong>：直接点击值单元格修改</li><li><strong>新增键值对</strong>：点击底部的「+ 添加请求头」按钮</li><li><strong>删除</strong>：点击行末的删除按钮</li></ul><blockquote><p>TODO: 截图 - 请求头编辑表格</p></blockquote><h4 id="请求体" tabindex="-1">请求体 <a class="header-anchor" href="#请求体" aria-label="Permalink to &quot;请求体&quot;">​</a></h4><p>一个代码编辑器（Monaco Editor），显示请求体 JSON 模板。你可以直接在其中编辑，变量 <code>{{variable}}</code> 会在发送时被替换。</p><blockquote><p>TODO: 截图 - 请求体编辑器</p></blockquote><h3 id="响应面板" tabindex="-1">响应面板 <a class="header-anchor" href="#响应面板" aria-label="Permalink to &quot;响应面板&quot;">​</a></h3><p>右侧的响应面板是查看 API 返回结果的地方。</p><h4 id="普通响应" tabindex="-1">普通响应 <a class="header-anchor" href="#普通响应" aria-label="Permalink to &quot;普通响应&quot;">​</a></h4><p>响应自上而下包含：</p><table tabindex="0"><thead><tr><th>区域</th><th>内容</th></tr></thead><tbody><tr><td><strong>状态栏</strong></td><td>HTTP 状态码（如 <code>200</code>）、状态文本（如 <code>OK</code>）、请求耗时（如 <code>1.23s</code>）</td></tr><tr><td><strong>响应头</strong></td><td>可折叠的响应头列表</td></tr><tr><td><strong>响应体</strong></td><td>自动语法高亮和格式化（JSON 自动美化，其他文本原样显示）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 普通响应面板，标注状态码、响应头和格式化的 JSON 响应体</p></blockquote><h4 id="流式响应" tabindex="-1">流式响应 <a class="header-anchor" href="#流式响应" aria-label="Permalink to &quot;流式响应&quot;">​</a></h4><p>当检测到响应 Content-Type 为 <code>text/event-stream</code> 或 <code>application/stream</code> 时，工具自动进入流式模式：</p><ul><li><strong>实时渲染</strong>：收到的每个数据块（chunk）会立即追加到响应体中</li><li><strong>持续更新</strong>：响应面板中的内容会不断刷新，你可以实时看到 LLM 逐字生成的过程</li><li><strong>手动中止</strong>：点击 URL 构建器的 <strong>停止</strong> 按钮可随时中断流式响应</li></ul><blockquote><p>TODO: 截图 - 流式响应进行中的状态，响应体内容在持续增长</p></blockquote><h3 id="请求档案管理" tabindex="-1">请求档案管理 <a class="header-anchor" href="#请求档案管理" aria-label="Permalink to &quot;请求档案管理&quot;">​</a></h3><p>点击顶部的 <strong>配置</strong> 按钮，打开请求档案管理对话框。</p><h4 id="保存当前配置" tabindex="-1">保存当前配置 <a class="header-anchor" href="#保存当前配置" aria-label="Permalink to &quot;保存当前配置&quot;">​</a></h4><ol><li>配置好预设、变量、请求头和请求体</li><li>点击 <strong>配置 → 保存当前配置</strong></li><li>输入配置名称（如 &quot;DeepSeek Chat 测试&quot;），点击确认</li><li>该配置会保存到浏览器本地存储中</li></ol><h4 id="加载已保存配置" tabindex="-1">加载已保存配置 <a class="header-anchor" href="#加载已保存配置" aria-label="Permalink to &quot;加载已保存配置&quot;">​</a></h4><p>在配置管理对话框中，你可以：</p><ul><li><strong>加载</strong>：选择一个已保存的配置，一键恢复所有设置</li><li><strong>重命名</strong>：修改配置名称</li><li><strong>删除</strong>：删除不再需要的配置</li></ul><blockquote><p>TODO: 截图 - 配置管理对话框，显示已保存的配置列表和操作按钮</p></blockquote><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="测试第三方兼容接口" tabindex="-1">测试第三方兼容接口 <a class="header-anchor" href="#测试第三方兼容接口" aria-label="Permalink to &quot;测试第三方兼容接口&quot;">​</a></h3><p>许多模型厂商（如 DeepSeek、DashScope、Moonshot、智谱、OpenRouter、Groq、xAI 等）提供与 OpenAI 兼容的 API。可以直接选择对应预设；如果服务商未内置，也可以使用 OpenAI Chat Completion 预设并修改两个变量：</p><ol><li><code>baseUrl</code> 改为第三方地址（如 <code>api.deepseek.com</code>）</li><li>在 <code>model</code> 变量的下拉框中手动输入或选择对应的模型名（如 <code>deepseek-chat</code>）</li></ol><blockquote><p>TODO: 截图 - 将 baseUrl 改为 api.deepseek.com，model 选择 deepseek-chat</p></blockquote><h3 id="gemini-流式与非流式切换" tabindex="-1">Gemini 流式与非流式切换 <a class="header-anchor" href="#gemini-流式与非流式切换" aria-label="Permalink to &quot;Gemini 流式与非流式切换&quot;">​</a></h3><p>Google Gemini API 的非流式和流式使用不同的端点（endpoint）：</p><table tabindex="0"><thead><tr><th>模式</th><th>endpoint 值</th></tr></thead><tbody><tr><td><strong>非流式</strong></td><td><code>generateContent</code></td></tr><tr><td><strong>流式</strong></td><td><code>streamGenerateContent</code></td></tr></tbody></table><p>使用 Gemini 预设时，变量列表中的 <code>endpoint</code> 变量可以选择 <code>generateContent</code> 或 <code>streamGenerateContent</code>，<code>stream</code> 布尔变量仅作为模板参考。确保两者的设置一致。</p><blockquote><p>💡 <strong>提示</strong>：流式响应即使到达 Gemini 的 <code>streamGenerateContent</code> 端点，工具的流式检测机制也能正常识别并实时渲染。</p></blockquote><h3 id="使用空白预设构建自定义请求" tabindex="-1">使用空白预设构建自定义请求 <a class="header-anchor" href="#使用空白预设构建自定义请求" aria-label="Permalink to &quot;使用空白预设构建自定义请求&quot;">​</a></h3><p>如果内置预设不能满足需求，可以选择 <strong>空白请求</strong> 预设从头开始：</p><ol><li>选择「空白请求」预设（默认方法为 GET）</li><li>在 URL 输入框中直接输入完整 URL</li><li>在请求配置面板中添加自定义请求头</li><li>根据需要填写请求体（GET 请求可留空）</li><li>点击发送</li></ol><blockquote><p>TODO: 截图 - 空白预设下，手动填写 URL 和请求头的示例</p></blockquote><h3 id="请求档案的多场景切换" tabindex="-1">请求档案的多场景切换 <a class="header-anchor" href="#请求档案的多场景切换" aria-label="Permalink to &quot;请求档案的多场景切换&quot;">​</a></h3><p>你在调试一个多模型的对比测试时可以这样用：</p><ol><li>用 OpenAI 预设配置好 GPT-4 的测试参数，保存为档案「GPT-4 测试」</li><li>将 <code>baseUrl</code> 改为 <code>api.deepseek.com</code>，<code>model</code> 改为 <code>deepseek-chat</code>，保存为「DeepSeek 测试」</li><li>在配置管理对话框中点击这两个档案即可快速切换测试不同的模型</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-我的-api-key-会被保存到哪里-安全吗" tabindex="-1">Q：我的 API Key 会被保存到哪里？安全吗？ <a class="header-anchor" href="#q-我的-api-key-会被保存到哪里-安全吗" aria-label="Permalink to &quot;Q：我的 API Key 会被保存到哪里？安全吗？&quot;">​</a></h3><p>API Key 会作为变量值保存在请求档案中，与档案一起存储在浏览器的 <code>localStorage</code> 中。<code>localStorage</code> 是浏览器本地存储，不会上传到任何服务器。但请注意，如果你清除了浏览器数据（包括本地存储），已保存的档案和其中包含的 API Key 也会一起丢失。建议勿将生产环境的高权限 Key 长期保存在配置中。</p><h3 id="q-为什么发送请求后一直卡住" tabindex="-1">Q：为什么发送请求后一直卡住？ <a class="header-anchor" href="#q-为什么发送请求后一直卡住" aria-label="Permalink to &quot;Q：为什么发送请求后一直卡住？&quot;">​</a></h3><p>可能的原因：</p><ul><li>API 地址不可达——检查 <code>baseUrl</code> 是否拼写正确、协议（<code>http://</code> vs <code>https://</code>）是否正确</li><li>网络代理问题——如果你处于需要代理的网络环境，确保应用已正确配置代理</li><li>API Key 无效或过期——<strong>大部分</strong> 4xx 错误会在响应中体现，但一些服务可能在认证失败时直接挂起连接</li><li>防火墙或跨域限制——桌面应用不受浏览器 CORS 限制，但可能受系统防火墙影响</li></ul><h3 id="q-流式响应不工作-响应体直接显示完整的-json-怎么办" tabindex="-1">Q：流式响应不工作，响应体直接显示完整的 JSON 怎么办？ <a class="header-anchor" href="#q-流式响应不工作-响应体直接显示完整的-json-怎么办" aria-label="Permalink to &quot;Q：流式响应不工作，响应体直接显示完整的 JSON 怎么办？&quot;">​</a></h3><p>检查以下两点：</p><ol><li>请求体中 <code>stream</code> 参数是否设置为 <code>true</code>（如果是 OpenAI/Claude 预设，打开变量中的 <code>stream</code> 开关）</li><li>响应的 <code>Content-Type</code> 是否包含 <code>text/event-stream</code>——某些网关或代理可能会改变 Content-Type，导致工具无法自动识别流式模式</li></ol><p>如果仍不行，可以手动验证：在终端中使用 <code>curl</code> 等工具发送相同请求，确认服务端是否确实返回了流式响应。</p><h3 id="q-新增的变量不生效-url-中的-myvar-没有被替换" tabindex="-1">Q：新增的变量不生效，URL 中的 <code>{{myVar}}</code> 没有被替换？ <a class="header-anchor" href="#q-新增的变量不生效-url-中的-myvar-没有被替换" aria-label="Permalink to &quot;Q：新增的变量不生效，URL 中的 `{{myVar}}` 没有被替换？&quot;">​</a></h3><p>检查变量名是否完全匹配（大小写敏感），以及变量是否添加到了当前预设的变量列表中。变量替换在发送请求时即时计算，如果 URL 模板中使用了 <code>{{myVar}}</code>，但变量列表中不存在 <code>myVar</code>，占位符会被原样保留在 URL 中。</p><p>你可以通过「配置 → 变量管理」添加自定义变量来解决此问题。</p><h3 id="q-为什么我保存的配置不见了" tabindex="-1">Q：为什么我保存的配置不见了？ <a class="header-anchor" href="#q-为什么我保存的配置不见了" aria-label="Permalink to &quot;Q：为什么我保存的配置不见了？&quot;">​</a></h3><p>已保存的请求档案存储在浏览器的 <code>localStorage</code> 中。以下情况会导致数据丢失：</p><ul><li>浏览器数据被清除（包括手动清除或自动清理工具）</li><li>应用通过 Tauri 升级后如果 localStorage 存储路径发生变化（概率较小）</li><li>同时打开多个标签页或应用实例时，后保存的配置可能覆盖先保存的同名配置</li></ul><p>建议定期将重要的配置手动截图或记录关键参数作为备份。</p></div>',1)])])}const g=t(l,[["render",d]]);export{u as __pageData,g as default};
